"use strict";(self.webpackChunktu_cis_4398_docs_template=self.webpackChunktu_cis_4398_docs_template||[]).push([["4522"],{91887:function(e){e.exports=JSON.parse('{"project":{"title":"AACcommodate API","description":"This application programming interface (API) supports AAC games. The API allows users to play AAC games like StoryQuest through external AAC board interaction, rather than relying on an embedded AAC board in the game. Users can relay game inputs by either speaking verbally or speaking through the board. The API will enable audio-controlled games, which will promote social and communication skills in children who use AAC devices by enabling AAC users to play games alongside non-AAC users.","source":"https://github.com/Capstone-Projects-2025-Fall/project-001-aac-api","documentation":"https://capstone-projects-2025-fall.github.io/project-001-aac-api/","website":"https://www.npmjs.com/package/aac-voice-api","tags":["aac","accessibility","games","api","communication","library","speech-to-text","typescript","javascript","python","devops","embedded","game","pwa","social"],"semester":"Fall 2025","slug":"aaccommodate","members":["Michael Colbert","Jessica Hutchison","Hena Patel","Gino Russo","Tam Trang"],"useDocsAsPreview":false},"routeSlug":"aaccommodate","canonicalSlug":"aaccommodate"}')}}]);